import java.util.List;
import java.util.ArrayList;
import jetbrains.mps.ide.migration.MigrationSetup;
import jetbrains.mps.internal.collections.runtime.CollectionSequence;
import jetbrains.mps.ide.ThreadUtils;
import jetbrains.mps.smodel.ModelReadRunnable;
import org.junit.Assert;
import jetbrains.mps.testbench.junit.suites.TestMakeUtil;
import java.util.stream.Stream;
import com.intellij.openapi.vfs.VirtualFile;
import com.intellij.openapi.vfs.LocalFileSystem;
import com.intellij.openapi.vfs.VfsUtil;

@MPSLaunch
@ExtendWith(EnvironmentAwareExtension.class)
public class NoPendingMigrationsTest extends EnvironmentAwareTestCase {
  private static final Logger LOG = Logger.getLogger(NoPendingMigrationsTest.class);
  private static final String MARKER_FILE_NAME = ".allow-pending-migrations";

  private File myProjectDir;
  private Project myProject;

  public NoPendingMigrationsTest() {
    // this test requires IDEA env configured withJavaPlugin().withMigrationPlugin()
    // java plugin is necessary just for testCloneModule project migration check as the project uses java_source_stubs
    // withMigrationPlugin() has to include plugin with mps-project-migrations for this test to make any sense
  }

  @ParameterizedTest
  @MethodSource
  public void noMigrationNeeded(String projectDir) {
    myProjectDir = new File(projectDir);
    try {
      openProject();
      _noMigrationNeeded();
    } finally {
      closeProject();
    }
  }

  public void _noMigrationNeeded() {
    if (new File(myProjectDir, MARKER_FILE_NAME).exists()) {
      if (LOG.isInfoLevel()) {
        LOG.info("Project " + myProjectDir.getName() + ": automatic migrations are not allowed (" + MARKER_FILE_NAME + " file is present in project dir)");
      }
      return;
    } else {
      if (LOG.isInfoLevel()) {
        LOG.info("Project " + myProjectDir.getName() + ": should be tested");
      }
    }
    final boolean[] migrationRequired = new boolean[]{false, false};
    final List<String> projectMigrations = new ArrayList<>();
    final List<String> moduleMigrations = new ArrayList<>();
    Runnable prepare = () -> {
      {
        final MigrationSetup migrationManager = new MigrationSetup(getContextProject());
        migrationRequired[0] = migrationManager.importVersionsUpdateRequired();
        migrationRequired[1] = migrationManager.isMigrationRequired();
        if (migrationRequired[1]) {
          CollectionSequence.fromCollection(migrationManager.getProjectMigrations()).select((this0) -> this0.getDescription()).visitAll((p1) -> projectMigrations.add(p1));
          CollectionSequence.fromCollection(migrationManager.getModuleMigrations()).select((this0) -> this0.caption()).visitAll((p1) -> moduleMigrations.add(p1));
        }
      }
    };
    Exception exception = ThreadUtils.runInUIThreadAndWait(new ModelReadRunnable(getContextProject().getRepository(), prepare));
    if (exception != null) {
      throw new RuntimeException(exception);
    }
    StringBuilder message = new StringBuilder("Pending:\n");
    if (migrationRequired[0]) {
      message.append("Module re-saving required\n");
    }
    message.append("Project migrations:\n");
    for (String pm : projectMigrations) {
      message.append(pm).append("\n");
    }
    message.append("Module migrations:\n");
    for (String mm : moduleMigrations) {
      message.append(mm).append("\n");
    }
    message.append("Project: ").append(getContextProject().getName()).append("\n");
    Assert.assertFalse(message.toString(), migrationRequired[0] || migrationRequired[1]);
  }

  private void openProject() {
    myProject = myEnvironment.openProject(myProjectDir);
    new TestMakeUtil(myEnvironment.getPlatform()).make(myProject);
  }

  private void closeProject() {
    myEnvironment.closeProject(myProject);
  }

  public Project getContextProject() {
    return myProject;
  }

  private static Stream<String> noMigrationNeeded() {
    // this method supplies parameters for the test method with the same name

    String projectsDir = System.getProperty("projects_dir");
    Assert.assertNotNull("Need system property 'projects_dir'", projectsDir);
    VirtualFile projectsRoot = LocalFileSystem.getInstance().findFileByPath(projectsDir);


    final Stream.Builder<String> projects = Stream.builder();
    VfsUtil.processFilesRecursively(projectsRoot, (VirtualFile file) -> {
      if (!(file.isValid()) || !(file.isDirectory())) {
        return true;
      }
      // is a project dir?
      if (!(file.getName().equals(com.intellij.openapi.project.Project.DIRECTORY_STORE_FOLDER))) {
        return true;
      }
      projects.add(file.getParent().getPath());
      return true;
    });

    return projects.build();
  }

}
